var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그 많은 녀석들을 혼자 때려눕히다니…!","JPN":"あの大勢のやつらを一人で倒すなんて……！","ENG":"She knocked out all those thugs by herself...!","TWN":"她一個人就把那些人都打趴咧…！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"엄청나. 역시 아카데미에서 인정 받은 엘리트 카운터다워.","JPN":"すごい。さすがアカデミーから認められたカウンターだな。","ENG":"Amazing. No wonder the Academy recognizes her as an elite.","TWN":"好強，不愧是受到學院認可的菁英制裁者。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"쳇, 애송이 녀석들과 비슷한 급인 줄 알았는데 착오였군.","JPN":"チッ、二人組のガキと似たようなランクだと思ったが､勘違いだったか。","ENG":"Tch, I guess I was wrong to assume you were on the same level as those idiots.","TWN":"嘖，我還以為你的實力和那二個小鬼差不多，是我誤會了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이제야 너희와 나의 격차를 알겠어? 알았으면 지금이라도 무릎 꿇고 빌어보라구.","JPN":"やっと私との実力の差に気付いた？　わかったなら、今からでも跪いて詫びてみなさいよ。","ENG":"Now you see the difference? It's not too late for you to kneel and beg for forgiveness.","TWN":"現在知道我和你們是不同層次的吧？那還不趕快跪下求饒！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>감히 아카데미 학생을 얕보고 덤벼서 죄송합니다</color>, 라고 말이야.","JPN":"<color=#ffd34c>アカデミーの生徒をなめて飛びかかって申し訳ありませんでした</color>、ってね。","ENG":"Say, <color=#ffd34c>\\"I'm sorry for underestimating an Academy student and attacking them.\\"</color>","TWN":"快點道歉說，<color=#ffd34c>對不起，我有眼不識泰山，竟敢招惹學院的學生</color>。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"...Sure.","TWN":"…好吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"우리가 졌다. 칼솜씨가 제법이군. 얕본 건 사과하지.","JPN":"俺らの負けだ。素晴らしい剣の腕前だな。なめたことは謝る。","ENG":"We admit defeat. Your skills are incredible. I apologize for misjudging you.","TWN":"是我們技不如人，你的刀法確實有兩下子，對不起，是我太小看你。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 장난해? 사과를 하고 싶은 거라면 그 꼿꼿한 허리부터 제대로 숙이라고.","JPN":"ふん、ふざけないでよ。謝るつもりなら、その腰をしっかり90度にかがめたら？","ENG":"Hmph, are you serious? If you're gonna apologize, do it properly and bow 90 degrees!","TWN":"哼，這算什麼道歉？道歉時要彎腰不是基本的嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"그런데 말이야…","JPN":"ところでさ……","ENG":"But I wonder...","TWN":"不過…"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"네 칼이 아무리 빨라도… 총알보다 빠를까…?","JPN":"いくらお前の剣が速くても……銃弾より速いかな……？","ENG":"If your sword... is faster than a bullet...?","TWN":"你的刀再怎麼快…快得過子彈嗎…？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…뭐?","JPN":"……は？","ENG":"...What?","TWN":"…蛤？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐라고 중얼거리는 거야? 잘 안 들리잖…","JPN":"何ぶつぶつ言っててるの？　よく聞こえな……","ENG":"What are you muttering? I can't hear you–","TWN":"你說什麼？我聽不清楚…"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으헥?!","JPN":"グホッ！？","ENG":"Eck?!","TWN":"哇啊？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"큭큭, 방심했군. 이 한 발을 위해 다가오길 기다렸지.","JPN":"ククッ、油断したな。この一発のために近づくのを待ってたんだ。","ENG":"Keke... You let your guard down. I was waiting for you to get closer to me.","TWN":"呵呵，你太大意了，為了射出這一發子彈，我一直在等你靠近呢。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"이걸로 한 놈은 처리…","JPN":"これで一人は片付け……","ENG":"That's one down, now...","TWN":"這樣就處理掉一個…"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"음?!","JPN":"むっ！？","ENG":"Huh?","TWN":"嗯？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…초음속 이터니움 할로우포인트탄.","JPN":"……超音速エタニウムホローポイント弾。","ENG":"...A supersonic Eternium hollow-point bullet.","TWN":"…超音速恆金空尖彈。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대는 살생을 목적으로 낭자의 머리를 정확히 노렸구려.","JPN":"貴殿は殺傷を目的に、彼女の頭を正確に狙っていたのですか。","ENG":"You aimed this at her head with the intention of killing her.","TWN":"你這一槍瞄準姑娘的頭，看來是真要取她性命。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"넌… 신입생?","JPN":"あんた……新入生？","ENG":"You're... the new kid?","TWN":"你…新生？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"내 탄환을… 그딴 막대기로 쳐냈다고?","JPN":"俺の弾丸を……あんな棒で打ち返した？","ENG":"You blocked my bullet... with that stick?","TWN":"你用那根棍子…就擋下我的子彈？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"넌 뭐야? 대체 어디서 나타난 거지?!","JPN":"お前は何だ？　いったいどこから現われたんだ！？","ENG":"What are you? Where did you come from?!","TWN":"你是誰？從哪冒出來的？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"싸움이 시작될 때부터 이곳에 있었다오.","JPN":"戦いが始まる時からここにいました。","ENG":"I was here from the moment the fight had started.","TWN":"你們打起來時在下便已經在此。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어?! 그럼 넌 우리가 싸우는 동안에도 구경만 하고 있었단 말이야?!","JPN":"はあ！？　じゃああんた、私たちが戦ってる間、ただ見物してたってこと！？","ENG":"What?! Then you were sitting back and watching while we were dealing with this guy?!","TWN":"什麼？！所以我剛在對付他們時，你就在旁邊湊熱鬧嗎？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"불필요한 개입을 피하기 위해 기척을 드러내지 않았을 뿐.","JPN":"不要な介入を避けるために、気配を隠していただけ。","ENG":"I merely chose to hide my presence to avoid any unnecessary interventions.","TWN":"因為還不到需要出手的時候，所以在下才沒有現身。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너도 아카데미 학생이잖아! 그럼 당연히 진작에 우릴 도왔어야지!","JPN":"あんたもアカデミーの生徒でしょ！　それなら、当然私たちのことを助けるべきでしょ！","ENG":"But you're also an Academy student! You should've helped us right away!","TWN":"你不也是學院的學生嗎！那應該早點出手幫忙吧！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"옳고 그름을 가릴 단서가 없는 경우, 단지 소속이 같다는 이유로 폭력에 가담하는 것은 옳지 않다오.","JPN":"善悪をわきまえる手がかりがない場合、ただ同じ所属であるという理由だけで暴力に加わることは正しいことではありません。","ENG":"With insufficient clues to distinguish right from wrong, it is not right to engage in violence simply because we are of the same affiliation.","TWN":"在還沒釐清狀況前，只因為都是學院的學生就貿然加入戰局，在下認為是不對的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"하지만, 저자의 명백한 살의는 개입할 명분이 됐지.","JPN":"ですが、あの者の殺意は介入する大義になりました。","ENG":"Nonetheless, my intervention was justified when he attempted to kill you.","TWN":"但對方露出殺意後，便給了在下出手的理由。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"큭… 어린 것이 건방 떨긴.","JPN":"くっ……ガキのくせに生意気だな。","ENG":"Kgh... You cocky little brats.","TWN":"嘖…小小年紀囂張什麼。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"쳇, 방금 소란 때문에 경찰까지 꼬인 건가?","JPN":"チッ、今の騒ぎで警察まで来たのか？","ENG":"Tch, I hear sirens. Are the cops coming as well?","TWN":"嘖，剛剛的騷動把條子也引過來了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"일단은 여기서 벗어나야… 으헉?!","JPN":"とりあえずはここから出ないと……うわっ！？","ENG":"I need to get out of here for now– Kuh?!","TWN":"總之先離開這裡…唔呃？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"왜… 몸이 움직이질 않지?","JPN":"なんで……体が動かねえんだ？","ENG":"Why... can't I move?","TWN":"我的身體…怎麼沒辦法動？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"마비혈을 자극해뒀소. 한동안 움직이지 못할 것이오.","JPN":"麻痺のツボを刺激しておきました。しばらく動けないでしょう。","ENG":"I pinched your paralysis points. You will not be able to move for a while.","TWN":"在下點了你穴，你的身體會暫時麻痺無法行動。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"마비혈…? 그딴 무협지에서나 나올 법한 헛소리를 믿으라고?","JPN":"麻痺のツボだと……？　そんなのは武侠小説の中の話だろ！","ENG":"Paralysis points...? You expect me to believe something that sounds like it came out of an Eastern fantasy novel?","TWN":"點穴…？你以為現在是在演武俠劇嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"살생이 미수에 그쳤으니, 목숨은 거두지 않겠지만 죄의 대가는 달게 받으시오.","JPN":"殺傷が未遂になりましたので殺さないでおきますが、罪は償ってください。","ENG":"Your killing ended only in an attempt. Thus, I will let you live, but you will pay for your sins.","TWN":"因為你殺人未遂，所以在下未取你性命，但還是必須為你的罪行付出代價。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"크윽…!","JPN":"くうっ……！","ENG":"Errgh...!","TWN":"呃呃…！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"너희! 지금 뭔 짓을 저지른 건지 알긴 하는 거냐?","JPN":"お前ら！　今何をしたのかわかってんのか？","ENG":"Hey! Do you even know what you've done?","TWN":"你們知道你們惹的是誰嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"변두리 패거리들을 전부 적으로 돌린 거다. 분명 후회하게 될 거야.","JPN":"街外れの連中を全員敵に回したんだ。きっと後悔することになるぞ。","ENG":"You've just turned all the gangs on the outskirts into your enemies! You're gonna regret this!","TWN":"你們現在可是與所有的幫派為敵，你們一定會後悔的！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"헹- 그딴 협박 하나도 안 무섭거든? 얌전히 잡혀 가서 콩밥이나 먹으시지!","JPN":"フーンだ。そんな脅し、全然怖くないのよ。大人しく捕まって牢屋にでも入いってなさいよね！","ENG":"Pfft! Your threats don't intimidate us! Now, it's time you went behind bars!","TWN":"哼，我好怕喔？才怪！你們乖乖去吃牢飯啦！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};